const input = $('Set Agent Input').first().json;
const raw = $json || {};
const normalizeDecision = (value) => String(value || '')
  .trim()
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

let normalized = raw;

if (typeof raw.output === 'object' && raw.output !== null) {
  normalized = raw.output;
} else if (typeof raw.output === 'string') {
  const text = raw.output.trim();

  if (text.startsWith('{') && text.endsWith('}')) {
    try {
      normalized = JSON.parse(text);
    } catch {
      normalized = { reply: text };
    }
  } else {
    normalized = { reply: text };
  }
} else if (typeof raw.text === 'string') {
  const text = raw.text.trim();

  if (text.startsWith('{') && text.endsWith('}')) {
    try {
      normalized = JSON.parse(text);
    } catch {
      normalized = { reply: text };
    }
  } else {
    normalized = { reply: text };
  }
}

const assistantReply = String(
  normalized.assistant_reply ||
  normalized.reply ||
  normalized.output ||
  normalized.text ||
  normalized.response ||
  ''
).trim();

const fallbackReply = input.message_type === 'imageMessage'
  ? 'Recebi sua imagem. Se quiser, posso te dizer objetivamente o que aparece nela e como isso se conecta com a sua duvida.'
  : input.message_type === 'audioMessage'
    ? 'Recebi seu audio. Se quiser, posso continuar a partir do que voce me falou.'
    : 'Como posso ajudar voce hoje?';

const finalReply = assistantReply || fallbackReply;
const decisionType = String(normalized.decision_type || '').trim();
const decisionValue = normalizeDecision(normalized.decision_value);
const rawInterestTopic = String(normalized.interest_topic || '').trim();
const normalizedInterestTopic = normalizeDecision(rawInterestTopic);
const interestTopic = normalizedInterestTopic === 'nenhum' ? '' : rawInterestTopic;
const summary = String(normalized.summary || normalized.reason || '').trim();
const explicitNeedFollowup = Boolean(normalized.need_followup || false);
const explicitNeedHandoff = Boolean(normalized.need_handoff || false);
const inferredNeedHandoff = decisionType === 'handoff_confirmation' && decisionValue === 'sim';
const inferredNeedFollowup = explicitNeedFollowup || decisionType === 'followup_offer' || (decisionType === 'handoff_confirmation' && decisionValue === 'nao');
const reason = String(normalized.reason || summary || decisionType || '').trim();

return {
  lead_phone: input.lead_phone,
  lead_name: input.lead_name,
  assistant_reply: finalReply,
  need_followup: inferredNeedFollowup,
  need_handoff: explicitNeedHandoff || inferredNeedHandoff,
  reason,
  summary,
  interest_topic: interestTopic,
  decision_type: decisionType,
  decision_value: decisionValue,
  is_client: normalized.is_client,
  dynamic_delay_seconds: Math.max(3, Math.min(10, Math.ceil(finalReply.length / 60)))
};

