const current = $('Wait Buffer Window').first().json;
const raw = $('Redis Get Buffer Final').first().json.buffer_list;

let entries = [];

if (Array.isArray(raw)) {
  entries = raw.filter(Boolean).map(v => String(v).trim()).filter(Boolean);
} else if (typeof raw === 'string') {
  entries = raw
    .split(',')
    .map(v => String(v).trim())
    .filter(Boolean);
}

const parsed = entries.map((entry) => {
  try {
    return JSON.parse(entry);
  } catch {
    return {
      spam_marker: false,
      message_id: '',
      message_text: entry,
      message_type: current.message_type,
      lead_phone: current.lead_phone,
      lead_name: current.lead_name,
    };
  }
});

const spamWarned = parsed.some((item) => item && item.spam_marker === true);
const messagesOnly = parsed.filter((item) => !(item && item.spam_marker === true));

const seen = new Set();
const dedup = [];
for (const item of messagesOnly) {
  const key = String(item.message_id || item.message_text || '').trim();
  if (!key || seen.has(key)) continue;
  seen.add(key);
  dedup.push(item);
}

const merged = dedup
  .map((item) => String(item.message_text || '').trim())
  .filter(Boolean)
  .join('\n')
  .trim() || String(current.message_text || '').trim();

return [
  {
    json: {
      lead_phone: current.lead_phone,
      lead_name: current.lead_name,
      message_type: current.message_type,
      message_id: current.message_id,
      merged_message: merged,
      merged_count: dedup.length || 1,
      spam_warned: spamWarned
    }
  }
];

const wrapped = $input.all()[0].json;
const source = wrapped['0'] || wrapped;

const imageText =
  source?.content?.[0]?.text ||
  source?.content?.['0']?.text ||
  source?.text ||
  '';

return [
  {
    json: {
      lead_phone: $('Normalize Input').first().json.lead_phone,
      lead_name: $('Normalize Input').first().json.lead_name,
      message_type: 'imageMessage',
      message_text: String(imageText).trim(),
      message_id: $('Normalize Input').first().json.message_id,
    }
  }
];

const raw = $json.output[0].content[0].text;

let parsed = [];

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = [{ part: 1, message: raw }];
}

parsed = Array.isArray(parsed) ? parsed : [{ part: 1, message: String(raw || '') }];

parsed = parsed
  .filter(item => item && item.message)
  .map((item, index) => ({
    part: Number(item.part || index + 1),
    message: String(item.message).trim(),
  }))
  .sort((a, b) => a.part - b.part);

return [
  {
    json: {
      output: parsed
    }
  }
];

const inputText = $json.message || '';

let sanitizedText = String(inputText).replace(/"/g, '');
sanitizedText = sanitizedText.replace(/\n/g, '\\n').trim();

return {
  json: {
    sanitizedText
  }
};
